 1→using System.IO;
 2→using System.Windows;
 3→using System.Windows.Threading;
 4→
 5→namespace TM12Viewer;
 6→
 7→public partial class App : Application
 8→{
 9→    protected override void OnStartup(StartupEventArgs e)
10→    {
11→        base.OnStartup(e);
12→
13→        // 전역 예외 핸들러
14→        DispatcherUnhandledException += App_DispatcherUnhandledException;
15→        AppDomain.CurrentDomain.UnhandledException += CurrentDomain_UnhandledException;
16→    }
17→
18→    private void App_DispatcherUnhandledException(object sender, DispatcherUnhandledExceptionEventArgs e)
19→    {
20→        LogCrash("DispatcherUnhandledException", e.Exception);
21→        MessageBox.Show($"예기치 않은 오류가 발생했습니다.\n{e.Exception.Message}", "오류",
22→            MessageBoxButton.OK, MessageBoxImage.Error);
23→        e.Handled = true;
24→    }
25→
26→    private void CurrentDomain_UnhandledException(object sender, UnhandledExceptionEventArgs e)
27→    {
28→        if (e.ExceptionObject is Exception ex)
29→            LogCrash("UnhandledException", ex);
30→    }
31→
32→    private static void LogCrash(string source, Exception ex)
33→    {
34→        try
35→        {
36→            var logPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "crash.log");
37→            var entry = $"[{DateTime.Now:yyyy-MM-dd HH:mm:ss}] [{source}]\n" +
38→                        $"Message: {ex.Message}\n" +
39→                        $"StackTrace: {ex.StackTrace}\n" +
40→                        $"---\n";
41→            File.AppendAllText(logPath, entry);
42→        }
43→        catch
44→        {
45→            // 로그 기록 실패 시 무시
46→        }
47→    }
48→}
