 32→        // 축 값 UI 배열 초기화
 33→        _jointTexts = [TxtJ1, TxtJ2, TxtJ3, TxtJ4, TxtJ5, TxtJ6];
 34→        _jointBars = [BarJ1, BarJ2, BarJ3, BarJ4, BarJ5, BarJ6];
 35→
 36→        // 로봇 3D 모델 초기화
 37→        _robotModel = new RobotModel();
 38→        Viewport3D.Children.Add(_robotModel.RootVisual);
 39→
 40→        // TCP 클라이언트 초기화
 41→        _client = new TmRobotClient();
 42→        _client.DataReceived += OnDataReceived;
 43→        _client.ConnectionChanged += OnConnectionChanged;
 44→        _client.LogMessage += OnLogMessage;
 45→
 46→        AddLog("TM12 Robot 3D Viewer 시작");
 47→
 48→        // 창 로드 후 카메라 자동 설정
 49→        Loaded += (_, _) => SetDefaultCamera();
 50→    }
