 74→    private async void BtnConnect_Click(object sender, RoutedEventArgs e)
 75→    {
 76→        _client.Host = TxtIp.Text.Trim();
 77→        if (int.TryParse(TxtPort.Text.Trim(), out int port))
 78→            _client.Port = port;
 79→
 80→        BtnConnect.IsEnabled = false;
 81→        await _client.ConnectAsync();
 82→    }
