 92→    /// <summary>
 93→    /// 데이터 수신 이벤트 (백그라운드 스레드에서 호출)
 94→    /// </summary>
 95→    private void OnDataReceived(double[] jointAngles, double[] tcpCoord)
 96→    {
 97→        Dispatcher.Invoke(() =>
 98→        {
 99→            // 3D 모델 업데이트
100→            _robotModel.SetAllJointAngles(jointAngles);
101→
102→            // 축 각도 UI 업데이트
103→            for (int i = 0; i < 6; i++)
104→            {
105→                _jointTexts[i].Text = $"{jointAngles[i]:F3}°";
106→                _jointBars[i].Value = jointAngles[i];
107→            }
108→
109→            // TCP 좌표 UI 업데이트
110→            TxtTcpX.Text = $"{tcpCoord[0]:F3} mm";
111→            TxtTcpY.Text = $"{tcpCoord[1]:F3} mm";
112→            TxtTcpZ.Text = $"{tcpCoord[2]:F3} mm";
113→            TxtTcpRx.Text = $"{tcpCoord[3]:F3}°";
114→            TxtTcpRy.Text = $"{tcpCoord[4]:F3}°";
115→            TxtTcpRz.Text = $"{tcpCoord[5]:F3}°";
116→
117→            // 갱신 주기 계산
118→            _updateCount++;
119→            var now = DateTime.Now;
120→            var elapsed = (now - _lastUpdateTime).TotalSeconds;
121→            if (elapsed >= 1.0)
122→            {
123→                _updateRate = _updateCount / elapsed;
124→                TxtUpdateRate.Text = $"갱신: {_updateRate:F1} Hz";
125→                _updateCount = 0;
126→                _lastUpdateTime = now;
127→            }
128→        });
129→    }
