131→    /// <summary>
132→    /// 연결 상태 변경 이벤트
133→    /// </summary>
134→    private void OnConnectionChanged(bool connected, string message)
135→    {
136→        Dispatcher.Invoke(() =>
137→        {
138→            if (connected)
139→            {
140→                TxtStatus.Text = "연결됨";
141→                TxtStatus.Foreground = new System.Windows.Media.SolidColorBrush(
142→                    System.Windows.Media.Color.FromRgb(0x90, 0xC0, 0x90));
143→                TxtEndpoint.Text = message;
144→                BtnConnect.IsEnabled = false;
145→                BtnDisconnect.IsEnabled = true;
146→                _lastUpdateTime = DateTime.Now;
147→                _updateCount = 0;
148→            }
149→            else
150→            {
151→                TxtStatus.Text = "미연결";
152→                TxtStatus.Foreground = new System.Windows.Media.SolidColorBrush(
153→                    System.Windows.Media.Color.FromRgb(0x90, 0x90, 0x90));
154→                TxtEndpoint.Text = "-";
155→                TxtUpdateRate.Text = "갱신: -";
156→                BtnConnect.IsEnabled = true;
157→                BtnDisconnect.IsEnabled = false;
158→            }
159→        });
160→    }
