174→    /// <summary>
175→    /// 로그 추가 (UI + 파일)
176→    /// </summary>
177→    private void AddLog(string message)
178→    {
179→        var entry = $"[{DateTime.Now:HH:mm:ss.fff}] {message}";
180→        LstLog.Items.Add(entry);
181→
182→        // 최대 500개 유지
183→        while (LstLog.Items.Count > 500)
184→            LstLog.Items.RemoveAt(0);
185→
186→        // 자동 스크롤
187→        LstLog.ScrollIntoView(LstLog.Items[^1]);
188→
189→        // 파일 기록
190→        try { File.AppendAllText(LogFilePath, entry + Environment.NewLine); }
191→        catch { /* 무시 */ }
192→    }
