  1→using System.IO;
  2→using System.Windows.Media;
  3→using System.Windows.Media.Media3D;
  4→using HelixToolkit.Wpf;
  5→
  6→namespace TM12Viewer.Robot;
  7→
  8→/// <summary>
  9→/// URDF 기반 TM12 로봇 6축 관절 체인.
 10→/// ModelVisual3D 중첩으로 kinematic chain 구성.
 11→/// </summary>
 12→public class RobotModel
 13→{
 14→    // 각 관절의 AxisAngleRotation3D (Angle 값만 변경하면 됨)
 15→    private readonly AxisAngleRotation3D[] _jointRotations = new AxisAngleRotation3D[6];
 16→
 17→
 18→    // 루트 ModelVisual3D (HelixViewport3D에 추가)
 19→    public ModelVisual3D RootVisual { get; }
 20→
 21→    // URDF 단위가 미터이므로 mm 변환 스케일
 22→    private const double SCALE = 1000.0;
 23→
 24→    public RobotModel()
 25→    {
 26→        // 관절 회전 초기화
 27→        for (int i = 0; i < 6; i++)
 28→            _jointRotations[i] = new AxisAngleRotation3D(new Vector3D(0, 0, 1), 0);
 29→
 30→        RootVisual = BuildKinematicChain();
 31→    }
 32→
 33→    // TM Robot 보고 각도 → URDF 각도 오프셋 (J2: +90°)
 34→    private static readonly double[] JointOffsets = [0, -90, 0, 0, 0, 0];
 35→
 36→    /// <summary>
 37→    /// 모든 관절 각도 설정 (도 단위, J1~J6)
 38→    /// </summary>
 39→    public void SetAllJointAngles(double[] angles)
 40→    {
 41→        for (int i = 0; i < Math.Min(angles.Length, 6); i++)
 42→            _jointRotations[i].Angle = angles[i] + JointOffsets[i];
 43→    }
 44→
 45→    /// <summary>
 46→    /// 개별 관절 각도 설정 (0-based index, 도 단위)
 47→    /// </summary>
 48→    public void SetJointAngle(int index, double angleDeg)
 49→    {
 50→        if (index >= 0 && index < 6)
 51→            _jointRotations[index].Angle = angleDeg;
 52→    }
 53→
 54→
 55→private ModelVisual3D BuildKinematicChain()
 56→    {
 57→        var material = CreateMaterial();
 58→        var modelsDir = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, "Models");
 59→
 60→        // link_0 (base) - 고정
 61→        var baseVisual = new ModelVisual3D();
 62→        var baseMesh = LoadStl(Path.Combine(modelsDir, "tm12-base.stl"));
 63→        if (baseMesh != null)
 64→            baseVisual.Children.Add(CreateMeshVisual(baseMesh, material));
 65→
 66→        // joint_1: origin=(0, 0, 0.1652) axis=Z
 67→        var joint1Visual = CreateJointVisual(
 68→            originXyz: new Vector3D(0, 0, 0.1652),
 69→            originRpy: new Vector3D(0, 0, 0),
 70→            jointIndex: 0);
 71→        var link1Mesh = LoadStl(Path.Combine(modelsDir, "tmr_750w_01.stl"));
 72→        if (link1Mesh != null)
 73→            joint1Visual.Children.Add(CreateMeshVisual(link1Mesh, material));
 74→        baseVisual.Children.Add(joint1Visual);
 75→
 76→        // joint_2: origin=(0, 0, 0) rpy=(-90°, -90°, 0) axis=Z
 77→        var joint2Visual = CreateJointVisual(
 78→            originXyz: new Vector3D(0, 0, 0),
 79→            originRpy: new Vector3D(-90, -90, 0),
 80→            jointIndex: 1);
 81→        var link2Mesh = LoadStl(Path.Combine(modelsDir, "tm12-arm1.stl"));
 82→        if (link2Mesh != null)
 83→            joint2Visual.Children.Add(CreateMeshVisual(link2Mesh, material));
 84→        joint1Visual.Children.Add(joint2Visual);
 85→
 86→        // joint_3: origin=(0.6361, 0, 0) axis=Z
 87→        var joint3Visual = CreateJointVisual(
 88→            originXyz: new Vector3D(0.6361, 0, 0),
 89→            originRpy: new Vector3D(0, 0, 0),
 90→            jointIndex: 2);
 91→        var link3Mesh = LoadStl(Path.Combine(modelsDir, "tm12-arm2.stl"));
 92→        if (link3Mesh != null)
 93→            joint3Visual.Children.Add(CreateMeshVisual(link3Mesh, material));
 94→        joint2Visual.Children.Add(joint3Visual);
 95→
 96→        // joint_4: origin=(0.5579, 0, -0.1563) rpy=(0, 0, 90°) axis=Z
 97→        var joint4Visual = CreateJointVisual(
 98→            originXyz: new Vector3D(0.5579, 0, -0.1563),
 99→            originRpy: new Vector3D(0, 0, 90),
100→            jointIndex: 3);
101→        var link4Mesh = LoadStl(Path.Combine(modelsDir, "tmr_100w_01.stl"));
102→        if (link4Mesh != null)
103→            joint4Visual.Children.Add(CreateMeshVisual(link4Mesh, material));
104→        joint3Visual.Children.Add(joint4Visual);
105→
106→        // joint_5: origin=(0, -0.106, 0) rpy=(90°, 0, 0) axis=Z
107→        var joint5Visual = CreateJointVisual(
108→            originXyz: new Vector3D(0, -0.106, 0),
109→            originRpy: new Vector3D(90, 0, 0),
110→            jointIndex: 4);
111→        var link5Mesh = LoadStl(Path.Combine(modelsDir, "tmr_100w_02.stl"));
112→        if (link5Mesh != null)
113→            joint5Visual.Children.Add(CreateMeshVisual(link5Mesh, material));
114→        joint4Visual.Children.Add(joint5Visual);
115→
116→        // joint_6: origin=(0, -0.11315, 0) rpy=(90°, 0, 0) axis=Z
117→        var joint6Visual = CreateJointVisual(
118→            originXyz: new Vector3D(0, -0.11315, 0),
119→            originRpy: new Vector3D(90, 0, 0),
120→            jointIndex: 5);
121→        var link6Mesh = LoadStl(Path.Combine(modelsDir, "tmr_ee.stl"));
122→        if (link6Mesh != null)
123→            joint6Visual.Children.Add(CreateMeshVisual(link6Mesh, material));
124→
125→        // OnRobot 툴 (mm 단위, 로봇 본체와 동일 재질)
126→        // Angle Bracket 90° (플랜지에 직접 장착)
127→        var abMesh = LoadStlMm(Path.Combine(modelsDir, "angle_bracket.stl"));
128→        if (abMesh != null)
129→        {
130→            var abVisual = CreateMeshVisual(abMesh, material);
131→            var abTransform = new Transform3DGroup();
132→            abTransform.Children.Add(new RotateTransform3D(
133→                new AxisAngleRotation3D(new Vector3D(1, 0, 0), -270)));
134→            abTransform.Children.Add(new ScaleTransform3D(-1, 1, 1));
135→            abVisual.Transform = abTransform;
136→            joint6Visual.Children.Add(abVisual);
137→        }
138→
139→        // Quick Changer (브라켓 볼트홀 면에 연결)
140→        var qcMesh = LoadStlMm(Path.Combine(modelsDir, "quick_changer_robot.stl"));
141→        if (qcMesh != null)
142→        {
143→            var qcVisual = CreateMeshVisual(qcMesh, material);
144→            var qcTransform = new Transform3DGroup();
145→            // QC +Y면 → +X 방향 (브라켓 볼트홀과 맞닿음)
146→            qcTransform.Children.Add(new RotateTransform3D(
147→                new AxisAngleRotation3D(new Vector3D(0, 0, 1), -90)));
148→            qcTransform.Children.Add(new TranslateTransform3D(-42, 0, 66));
149→            qcVisual.Transform = qcTransform;
150→            joint6Visual.Children.Add(qcVisual);
151→        }
152→
153→        // Screwdriver (QC tool side에 연결, X180° Z90°)
154→        var sdMesh = LoadStlMm(Path.Combine(modelsDir, "screwdriver.stl"));
155→        if (sdMesh != null)
156→        {
157→            var sdVisual = CreateMeshVisual(sdMesh, material);
158→            var sdTransform = new Transform3DGroup();
159→            sdTransform.Children.Add(new RotateTransform3D(
160→                new AxisAngleRotation3D(new Vector3D(1, 0, 0), 180)));
161→            sdTransform.Children.Add(new RotateTransform3D(
162→                new AxisAngleRotation3D(new Vector3D(0, 0, 1), 90)));
163→            sdTransform.Children.Add(new TranslateTransform3D(-53, 1, 72));
164→            sdVisual.Transform = sdTransform;
165→            joint6Visual.Children.Add(sdVisual);
166→        }
167→
168→        joint5Visual.Children.Add(joint6Visual);
169→
170→        return baseVisual;
171→    }
172→
173→    /// <summary>
174→    /// 관절 Visual 생성: URDF origin(xyz+rpy) 고정 변환 + 관절 회전
175→    /// WPF Transform3DGroup 적용 순서: 이동 → RPY 회전 → 관절 회전
176→    /// </summary>
177→    private ModelVisual3D CreateJointVisual(Vector3D originXyz, Vector3D originRpy, int jointIndex)
178→    {
179→        var visual = new ModelVisual3D();
180→        var transformGroup = new Transform3DGroup();
181→
182→        // 1) 관절 회전 (Z축 기준, 실시간 변경) — 가장 안쪽(로컬)
183→        transformGroup.Children.Add(new RotateTransform3D(_jointRotations[jointIndex]));
184→
185→        // 2) URDF origin rpy 고정 회전 (Z→Y→X 역순 적용)
186→        if (originRpy.X != 0 || originRpy.Y != 0 || originRpy.Z != 0)
187→        {
188→            if (originRpy.Z != 0)
189→                transformGroup.Children.Add(new RotateTransform3D(
190→                    new AxisAngleRotation3D(new Vector3D(0, 0, 1), originRpy.Z)));
191→            if (originRpy.Y != 0)
192→                transformGroup.Children.Add(new RotateTransform3D(
193→                    new AxisAngleRotation3D(new Vector3D(0, 1, 0), originRpy.Y)));
194→            if (originRpy.X != 0)
195→                transformGroup.Children.Add(new RotateTransform3D(
196→                    new AxisAngleRotation3D(new Vector3D(1, 0, 0), originRpy.X)));
197→        }
198→
199→        // 3) URDF origin xyz 이동 (미터 → mm 스케일 적용) — 가장 바깥쪽(부모 좌표)
200→        transformGroup.Children.Add(new TranslateTransform3D(
201→            originXyz.X * SCALE, originXyz.Y * SCALE, originXyz.Z * SCALE));
202→
203→        visual.Transform = transformGroup;
204→        return visual;
205→    }
