    public static async Task<string> Status(ComputeBoxClient cb) { ... }
    public static async Task<string> Recover(ComputeBoxClient cb) { ... }
    public static async Task<string> Raw(ComputeBoxClient cb, string[] args) { ... }
    // 확장
